Here's a test class using MSTest's comparison assertions for your `ScoreCalculator`:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);   // result > 0
        Assert.IsLessThan(100.0, result);    // result < 100
    }

    [TestMethod]
    public void NormalizeScore_PartialScore_IsInRange()
    {
        var result = _calculator.NormalizeScore(45.0, 60.0);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(120.0, 100.0);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    [DataRow(95.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    public void CalculatePercentage_TotalIsZero_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }
}
```

**Key comparison assertions used:**

| Assertion | Purpose |
|-----------|---------|
| `Assert.IsInRange(actual, low, high)` | Verify value falls within bounds |
| `Assert.IsGreaterThan(lowerBound, actual)` | Verify value exceeds a minimum |
| `Assert.IsLessThan(upperBound, actual)` | Verify value is below a maximum |

These give much better failure messages than `Assert.IsTrue(result > 0)` — on failure they report the actual value and the bound that was violated. Requires **MSTest 3.x+**.
